// App.tsx
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Helmet } from 'react-helmet';

import { AppSettings, defaultSettings } from './types';
import ChatInterface from './components/ChatInterface';
import { loadSettings, saveSettings } from './utils/settings';
import SettingsMenu from './components/settings/SettingsMenu';
import { AuthProvider } from './contexts/AuthContext';
import { RequireAuth } from './components/RequireAuth';
import Login from './components/auth/Login';
import SignUp from './components/auth/SignUp';
import { fetchCurrentUser, fetchLatestVersion } from './utils/api';
import { VersionCheck } from './components/VersionCheck';

function App() {
  const [settings, setSettings] = useState<AppSettings>(() => {
    const savedSettings = loadSettings();
    return savedSettings || defaultSettings;
  });
  const [apiKey, setApiKey] = useState<string | null>(null);
  const [version, setVersion] = useState<string | null>(null);
  const { t } = useTranslation();

  useEffect(() => {
    saveSettings(settings);
  }, [settings]);

  useEffect(() => {
    const fetchVersion = async () => {
      try {
        const latestVersion = await fetchLatestVersion();
        setVersion(latestVersion);
      } catch (error) {
        console.error('Failed to fetch latest version:', error);
      }
    };

    fetchVersion();
  }, []);

  const handleSettingsChange = (newSettings: Partial<AppSettings>) => {
    setSettings((prevSettings) => ({
      ...prevSettings,
      ...newSettings,
    }));
  };

  return (
    <Router>
      <AuthProvider>
        <Helmet>
          <title>{t('app.title')}</title>
        </Helmet>
        <div className="App">
          <Routes>
            <Route path="/login" element={<Login />} />
            <Route path="/signup" element={<SignUp />} />
            <Route path="/" element={<RequireAuth><ChatInterface showModelName={settings.showModelName ?? true} settings={settings} onSettingsChange={handleSettingsChange} apiKey={apiKey} setApiKey={setApiKey} /></RequireAuth>} />
            <Route path="/settings" element={<RequireAuth><SettingsMenu settings={settings} onSettingsChange={handleSettingsChange} /></RequireAuth>} />
          </Routes>
          {version && <VersionCheck currentVersion={process.env.REACT_APP_VERSION || '0.0.0'} latestVersion={version} />}
        </div>
      </AuthProvider>
    </Router>
  );
}

export default App;

