"use client";

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { GeminiService } from './services/geminiService';
import { Message, Role, GeminiModel, AppSettings, ChatSession, KeyConfig, ToastMessage, DialogConfig, APP_VERSION } from './types';
import Sidebar from './components/Sidebar';
import { Header } from './components/Header';
import ChatInterface from './components/ChatInterface';
import ChatInput from './components/ChatInput';
import SettingsModal from './components/SettingsModal';
import MobileMenu from './components/MobileMenu';
import SecurityLock from './components/SecurityLock';
import { t } from './utils/i18n';
import { ToastContainer } from './components/ui/Toast';
import { CustomDialog } from './components/ui/CustomDialog';
import { executeFilterScript } from './utils/scriptExecutor';

const DEFAULT_SETTINGS: AppSettings = {
  defaultModel: GeminiModel.FLASH,
  defaultBaseUrl: 'https://api.openai.com/v1',
  systemPrompts: [],
  theme: 'light',
  language: 'en',
  fontSize: 16,
  textWrapping: 'default',
  bubbleTransparency: 100,
  showModelName: true,
  security: {
    enabled: false,
    questions: [],
    lastLogin: 0,
    lockoutDurationSeconds: 86400, // 24 hours
  },
  generation: {
    temperature: 0.7,
    topP: 0.95,
    topK: 64,
    maxOutputTokens: 8192,
    stream: true,
  },
  scripts: {
    inputFilterEnabled: false,
    inputFilterCode: '',
    outputFilterEnabled: false,
    outputFilterCode: ''
  }
};

const DEFAULT_KEYS: KeyConfig[] = [];

const App: React.FC = () => {
  // State
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string>('');
  const [apiKeys, setApiKeys] = useState<KeyConfig[]>(DEFAULT_KEYS);
  const [settings, setSettings] = useState<AppSettings>(DEFAULT_SETTINGS);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSummarizing, setIsSummarizing] = useState(false);

  // Security State
  const [isSecurityLocked, setIsSecurityLocked] = useState(false);

  // UI Components State
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [dialog, setDialog] = useState<DialogConfig>({
    isOpen: false,
    type: 'alert',
    title: '',
    onConfirm: () => {}
  });

  const abortControllerRef = useRef<AbortController | null>(null);
  const geminiServiceRef = useRef<GeminiService | null>(null);

  // Initialize Service
  if (!geminiServiceRef.current) {
    geminiServiceRef.current = new GeminiService(apiKeys);
  }

  // Toast Handler
  const addToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    const id = uuidv4();
    setToasts(prev => [...prev, { id, message, type }]);
  };

  const removeToast = (id: string) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  };

  // Dialog Handler
  const showDialog = (config: Partial<DialogConfig> & { title: string, onConfirm: (value?: string) => void }) => {
    setDialog({
      isOpen: true,
      type: 'alert',
      message: '',
      inputValue: '',
      inputPlaceholder: '',
      onCancel: () => {},
      ...config
    });
  };

  const closeDialog = () => {
    setDialog(prev => ({ ...prev, isOpen: false }));
  };

  // Update Service when keys change
  useEffect(() => {
    if (geminiServiceRef.current) {
      geminiServiceRef.current.updateKeys(apiKeys);
    }
  }, [apiKeys]);

  // Load Data
  useEffect(() => {
    const loadedSettings = localStorage.getItem('omnichat_settings');
    if (loadedSettings) {
      try {
        const parsed = JSON.parse(loadedSettings);
        setSettings({ ...DEFAULT_SETTINGS, ...parsed });

        // Apply theme immediately
        const root = document.documentElement;
        root.classList.remove('dark', 'theme-dark', 'theme-light', 'theme-twilight', 'theme-sky', 'theme-pink');
        root.classList.add(`theme-${parsed.theme || 'light'}`);
        if (['dark', 'twilight'].includes(parsed.theme)) {
           root.classList.add('dark');
        }
      } catch (e) { console.error("Failed to load settings", e); }
    }

    const loadedKeys = localStorage.getItem('omnichat_keys');
    if (loadedKeys) {
      try {
        setApiKeys(JSON.parse(loadedKeys));
      } catch (e) { console.error("Failed to load keys", e); }
    }

    const loadedSessions = localStorage.getItem('omnichat_sessions');
    if (loadedSessions) {
      try {
        const parsed = JSON.parse(loadedSessions);
        setSessions(parsed);
        if (parsed.length > 0) {
          setCurrentSessionId(parsed[0].id);
        } else {
          createNewSession();
        }
      } catch (e) { 
        console.error("Failed to load sessions", e);
        createNewSession();
      }
    } else {
      createNewSession();
    }
  }, []);

  // Save Data
  useEffect(() => {
    localStorage.setItem('omnichat_settings', JSON.stringify(settings));
  }, [settings]);

  useEffect(() => {
    localStorage.setItem('omnichat_keys', JSON.stringify(apiKeys));
  }, [apiKeys]);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('omnichat_sessions', JSON.stringify(sessions));
    }
  }, [sessions]);

  // Security Lock Logic
  useEffect(() => {
    if (settings.security.enabled) {
      const now = Date.now();
      const lockoutDuration = (settings.security.lockoutDurationSeconds || 86400) * 1000;
      if (now - settings.security.lastLogin > lockoutDuration) {
        setIsSecurityLocked(true);
      }
    }
  }, [settings.security.enabled, settings.security.lastLogin, settings.security.lockoutDurationSeconds]);

  const handleUnlock = () => {
    setIsSecurityLocked(false);
    setSettings(prev => ({
      ...prev,
      security: { ...prev.security, lastLogin: Date.now() }
    }));
  };

  const createNewSession = () => {
    const newSession: ChatSession = {
      id: uuidv4(),
      title: t('msg.new_chat_title', settings.language),
      messages: [],
      createdAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    if (window.innerWidth < 768) setIsMobileMenuOpen(false);
  };

  const updateCurrentSessionMessages = (messages: Message[]) => {
    setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, messages } : s));
  };

  const currentSession = sessions.find(s => s.id === currentSessionId) || sessions[0];

  const handleSendMessage = async () => {
    if (!input.trim() || !geminiServiceRef.current) return;

    const activeKeys = apiKeys.filter(k => k.isActive);
    if (activeKeys.length === 0) {
      addToast(t('input.no_keys', settings.language), 'error');
      return;
    }

    // 1. Input Filter (Middleware)
    let processedInput = input;
    if (settings.scripts.inputFilterEnabled && settings.scripts.inputFilterCode) {
        processedInput = executeFilterScript(settings.scripts.inputFilterCode, input, {
            role: 'user',
            history: currentSession?.messages || []
        });
    }

    const newMessage: Message = {
      id: uuidv4(),
      role: Role.USER,
      text: processedInput,
      timestamp: Date.now()
    };

    const updatedMessages = [...(currentSession?.messages || []), newMessage];
    updateCurrentSessionMessages(updatedMessages);
    setInput('');
    setIsLoading(true);

    // Initial placeholder for AI response
    const botMessageId = uuidv4();
    const botMessagePlaceholder: Message = {
      id: botMessageId,
      role: Role.MODEL,
      text: '', // Start empty
      timestamp: Date.now()
    };
    updateCurrentSessionMessages([...updatedMessages, botMessagePlaceholder]);

    await triggerBotResponse([...updatedMessages], botMessageId);
  };

  const triggerBotResponse = async (history: Message[], botMessageId: string) => {
    abortControllerRef.current = new AbortController();

    try {
      let accumulatedText = "";

      const systemInstruction = settings.systemPrompts
        .filter(p => p.isActive)
        .map(p => p.content)
        .join('\n\n');

      const { text, usedKeyIndex, provider, usedModel } = await geminiServiceRef.current!.streamChatResponse(
        settings.defaultModel, // Pass default, but service prefers key-specific model
        history,
        history[history.length - 1].text, // Latest user message
        systemInstruction,
        settings.generation,
        (chunk) => {
           // 2. Output Filter (Middleware) - Streaming
           let processedChunk = chunk;
           if (settings.scripts.outputFilterEnabled && settings.scripts.outputFilterCode) {
               processedChunk = executeFilterScript(settings.scripts.outputFilterCode, chunk, {
                   role: 'model',
                   history: history
               });
           }
           accumulatedText = processedChunk;

           setSessions(prev => prev.map(s => {
            if (s.id === currentSessionId) {
              return {
                ...s,
                messages: s.messages.map(m => 
                  m.id === botMessageId ? { ...m, text: processedChunk } : m
                )
              };
            }
            return s;
           }));
        },
        abortControllerRef.current.signal
      );

      // 2. Output Filter (Middleware) - Final
      let finalText = text;
      if (settings.scripts.outputFilterEnabled && settings.scripts.outputFilterCode) {
          finalText = executeFilterScript(settings.scripts.outputFilterCode, text, {
              role: 'model',
              history: history
          });
      }

      setSessions(prev => prev.map(s => {
        if (s.id === currentSessionId) {
          return {
            ...s,
            messages: s.messages.map(m => 
              m.id === botMessageId ? { 
                  ...m, 
                  text: finalText, 
                  keyIndex: usedKeyIndex,
                  provider: provider,
                  model: usedModel
              } : m
            )
          };
        }
        return s;
      }));

    } catch (error: any) {
      if (error.message === 'Aborted by user') return;

      const errorMessage = `Error: ${error.message || 'Unknown error'}`;
      setSessions(prev => prev.map(s => {
        if (s.id === currentSessionId) {
          return {
            ...s,
            messages: s.messages.map(m => 
              m.id === botMessageId ? { ...m, text: errorMessage, isError: true } : m
            )
          };
        }
        return s;
      }));
      addToast(t('msg.connection_failed', settings.language), 'error');
    } finally {
      setIsLoading(false);
      abortControllerRef.current = null;
    }
  };

  const handleStop = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      setIsLoading(false);
    }
  };

  const handleEditMessage = (id: string, newText: string) => {
    const updatedMessages = currentSession.messages.map(m => m.id === id ? { ...m, text: newText } : m);
    updateCurrentSessionMessages(updatedMessages);
  };

  const handleDeleteMessage = (id: string) => {
    const updatedMessages = currentSession.messages.filter(m => m.id !== id);
    updateCurrentSessionMessages(updatedMessages);
  };

  const handleRegenerate = async (id: string) => {
    // Find index of message to regenerate
    const index = currentSession.messages.findIndex(m => m.id === id);
    if (index === -1) return;

    // If it's a user message, we want to regenerate the response AFTER it
    // If it's a model message, we want to regenerate IT (replace it) based on history BEFORE it

    let historyToUse: Message[] = [];
    let botMessageId = uuidv4();

    if (currentSession.messages[index].role === Role.USER) {
        // User message: keep up to this message, discard anything after, add new bot placeholder
        historyToUse = currentSession.messages.slice(0, index + 1);
    } else {
        // Model message: keep history up to the message BEFORE this one
        historyToUse = currentSession.messages.slice(0, index);
        // We reuse the ID if we want to replace, OR create new. Let's create new to be clean.
    }

    const botMessagePlaceholder: Message = {
        id: botMessageId,
        role: Role.MODEL,
        text: '',
        timestamp: Date.now()
    };

    const newMessagesState = [...historyToUse, botMessagePlaceholder];
    updateCurrentSessionMessages(newMessagesState);

    setIsLoading(true);
    await triggerBotResponse(historyToUse, botMessageId);
  };

  const handleDeleteSession = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    showDialog({
        type: 'confirm',
        title: t('action.delete', settings.language),
        message: t('action.confirm_delete', settings.language),
        onConfirm: () => {
            const newSessions = sessions.filter(s => s.id !== id);
            setSessions(newSessions);
            if (currentSessionId === id) {
                if (newSessions.length > 0) setCurrentSessionId(newSessions[0].id);
                else createNewSession();
            }
            addToast("Chat deleted", 'success');
        }
    });
  };

  const handleRenameSession = () => {
      showDialog({
          type: 'input',
          title: t('msg.rename_chat', settings.language),
          inputValue: currentSession.title,
          onConfirm: (val) => {
              if (val) {
                  setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, title: val } : s));
              }
          }
      });
  };

  const handleSaveChat = () => {
    const data = {
        title: currentSession.title,
        messages: currentSession.messages,
        version: 1
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `chat_${currentSession.title.replace(/\s+/g, '_')}_${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    addToast("Chat saved to file", 'success');
  };

  const handleLoadSession = (messages: any[], title?: string) => {
      const newSession: ChatSession = {
          id: uuidv4(),
          title: title || `Imported Chat ${new Date().toLocaleTimeString()}`,
          messages: messages.map((m: any) => ({ ...m, id: m.id || uuidv4() })),
          createdAt: Date.now()
      };
      setSessions(prev => [newSession, ...prev]);
      setCurrentSessionId(newSession.id);
      addToast("Chat loaded from file", 'success');
  };

  const handleSummarize = async () => {
    if (!currentSession.messages.length || !geminiServiceRef.current) return;
    setIsSummarizing(true);
    try {
        const textToSummarize = currentSession.messages.map(m => `${m.role}: ${m.text}`).join('\n').slice(0, 5000); // Limit context
        // Temporary specialized generation config
        const summary = await geminiServiceRef.current.streamChatResponse(
            settings.defaultModel,
            [],
            t('msg.summarize_prompt', settings.language) + `\n\n${textToSummarize}`,
            undefined, 
            { ...settings.generation, stream: false, maxOutputTokens: 50 },
            undefined
        );

        let newTitle = summary.text.trim().replace(/^["']|["']$/g, ''); // Remove quotes
        if (newTitle) {
            setSessions(prev => prev.map(s => s.id === currentSessionId ? { ...s, title: newTitle } : s));
            addToast("Chat summarized", 'success');
        }
    } catch (e) {
        addToast(t('msg.summarize_error', settings.language), 'error');
    } finally {
        setIsSummarizing(false);
    }
  };

  if (isSecurityLocked) {
      return (
          <>
            <div className={`fixed inset-0 bg-background-start transition-colors duration-500`}></div>
            <SecurityLock 
                config={settings.security} 
                onUnlock={handleUnlock} 
                lang={settings.language} 
            />
          </>
      );
  }

  const activeKeysCount = apiKeys.filter(k => k.isActive).length;

  return (
    <div className={`flex h-full text-gray-900 dark:text-white transition-colors duration-500`}>
      <ToastContainer toasts={toasts} removeToast={removeToast} />
      <CustomDialog config={dialog} onClose={closeDialog} lang={settings.language} />

      {/* Sidebar (Desktop) */}
      <Sidebar 
        sessions={sessions}
        activeSessionId={currentSessionId}
        activeKeysCount={activeKeysCount}
        language={settings.language}
        onNewChat={createNewSession}
        onSelectSession={(id) => { setCurrentSessionId(id); }}
        onDeleteSession={handleDeleteSession}
        onOpenSettings={() => setIsSettingsOpen(true)}
      />

      {/* Mobile Menu Overlay */}
      <MobileMenu 
        isOpen={isMobileMenuOpen}
        sessions={sessions}
        activeSessionId={currentSessionId}
        language={settings.language}
        onClose={() => setIsMobileMenuOpen(false)}
        onNewChat={createNewSession}
        onSelectSession={(id) => { setCurrentSessionId(id); setIsMobileMenuOpen(false); }}
        onDeleteSession={handleDeleteSession}
        onOpenSettings={() => setIsSettingsOpen(true)}
      />

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full relative overflow-hidden">
        <Header 
          currentSessionTitle={currentSession?.title || t('msg.new_chat_title', settings.language)}
          isSummarizing={isSummarizing}
          hasMessages={currentSession?.messages.length > 0}
          language={settings.language}
          onRename={handleRenameSession}
          onSummarize={handleSummarize}
          onOpenMobileMenu={() => setIsMobileMenuOpen(true)}
          onNewChat={createNewSession}
          onOpenSettings={() => setIsSettingsOpen(true)}
          onSaveChat={handleSaveChat}
