          onSend={handleSendMessage} 
          onStop={handleStop}
          isLoading={isLoading}
          isDisabled={activeKeysCount === 0 && !settings.scripts.inputFilterEnabled} // Allow input if scripts are enabled even if no keys (dev mode)
          fontSize={settings.fontSize}
          language={settings.language}
